function afficherNotesValides(notes) {
  for (let i = 0; i < notes.length; i++) {
    const note = notes[i];
    if (typeof note !== 'number' || note < 0 || note > 20) {
      continue; // Ignorer les notes invalides
    }
    console.log(note);
  }
}

